<template><div class="panel"><div class="section-head"><div><h2>{{ t('settings.title') }}</h2><p>{{ t('settings.description') }}</p></div><el-button v-if="auth.hasPermission('system:setting:create')" type="primary" @click="open()">{{ t('settings.add') }}</el-button></div><el-table :data="rows"><el-table-column prop="groupCode" :label="t('settings.group')"/><el-table-column prop="configKey" :label="t('settings.key')"/><el-table-column prop="name" :label="t('common.name')"/><el-table-column prop="configValue" :label="t('settings.value')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button link type="primary" @click="open(s.row)">{{ t('common.edit') }}</el-button><el-button link type="danger" @click="remove(s.row)">{{ t('common.delete') }}</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?t('settings.edit'):t('settings.add')"><el-form label-width="90px"><el-form-item :label="t('settings.group')"><el-input v-model="form.groupCode"/></el-form-item><el-form-item :label="t('settings.key')"><el-input v-model="form.configKey"/></el-form-item><el-form-item :label="t('common.name')"><el-input v-model="form.name"/></el-form-item><el-form-item :label="t('settings.value')"><el-input v-model="form.configValue" :placeholder="form.sensitive&&form.id?t('settings.keepValue'):''"/></el-form-item><el-form-item :label="t('settings.sensitive')"><el-switch v-model="form.sensitive"/></el-form-item><el-form-item :label="t('common.enabled')"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">{{ t('common.cancel') }}</el-button><el-button type="primary" @click="save">{{ t('common.save') }}</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';import{useAuthStore}from'../stores/auth';const{t}=useI18n();const auth=useAuthStore(),rows=ref([]),visible=ref(false),form=reactive({id:null,groupCode:'system',configKey:'',name:'',configValue:'',sensitive:false,enabled:true});async function load(){rows.value=(await http.get('/system/settings')).data}/** 打开参数窗口。 */function open(row){Object.assign(form,row?{...row,configValue:row.sensitive?'':row.configValue}:{id:null,groupCode:'system',configKey:'',name:'',configValue:'',sensitive:false,enabled:true});visible.value=true}/** 保存参数。 */async function save(){form.id?await http.put(`/system/settings/${form.id}`,form):await http.post('/system/settings',form);visible.value=false;await load();ElMessage.success(t('common.successSaved'))}/** 删除参数。 */async function remove(row){await ElMessageBox.confirm(t('common.confirmDelete',{name:row.configKey}),t('common.deleteConfirm'),{type:'warning'});await http.delete(`/system/settings/${row.id}`);await load();ElMessage.success(t('common.successDeleted'))}onMounted(load)</script>
